export function t(key: string, params: Record<string, string | number> = {}): string {
  const language = settingsStore.current.ui_language as UiLanguage;
  const entry = translations[language]?.[key] ?? studyTranslations[language]?.[key] ?? translations.de[key] ?? studyTranslations.de[key];
  if (!entry) return language === "de" ? key : phrases[key]?.[language] ?? key;
  return typeof entry === "function" ? entry(params) : entry;
}

